THE CLAIM:
{
 "title": "Bundled PDUs shrink the winnable pool below the model's floor",
 "narrative": "The model assumes there is a pool of standalone rack-PDU purchases a new entrant can compete for, sized at 0.5 to 3% of the market. But the incumbents who sell the $23B power and $26B cooling packages bundle the PDUs inside those deals, and the only standalone tenders found were tiny and barely contested. That pushes the real Year-1 share to about 0.3%, below the model's own 0.5% floor.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Incumbents bundle PDUs into power and cooling deals at zero margin",
   "refs": [
    "digest:cust-mix#c2",
    "digest:cust-mix#c3",
    "ledger:shape.cr3"
   ]
  },
  {
   "step": "propagation",
   "text": "Leftover standalone tenders are small, sole-sourced, or barely contested",
   "refs": [
    "digest:obtainable-benchmark#c1",
    "digest:obtainable-benchmark#c6",
    "digest:obtainable-benchmark#c7"
   ]
  },
  {
   "step": "model-impact",
   "text": "Real Year-1 share drops to about 0.3%, below the floor",
   "refs": [
    "ledger:obtainableFactor",
    "digest:obtainable-benchmark#c10",
    "digest:obtainable-benchmark#c0"
   ]
  }
 ],
 "falsifier": "A logged pipeline of five or more standalone, multi-vendor rack-PDU tenders in CE-7, each at least €250K, within any six-month window, where a non-incumbent can bid.",
 "category": "execution",
 "evidence": [
  {
   "title": "Beschaffung von Stromverteilereinheiten (PDU) — Direct Award, Stadt Zürich",
   "sourceType": "industry-report",
   "publisher": "it-beschaffung.ch / Stadt Zürich OIZ",
   "date": "2024-07-04",
   "excerpt": "Beschaffung von 900 Stromverteilereinheiten... Awards: Riedo Networks AG CHF 1,996,000. Marktabklärungen zeigten, dass nur eine Firma PDU anbieten kann... Die Vergabe erfolgt somit freihändig.",
   "url": "https://www.it-beschaffung.ch/564/beschaffung-von-stromverteilereinheiten-pdu",
   "attached": true
  },
  {
   "title": "Serviceable Obtainable Market (SOM): How to Calculate It",
   "sourceType": "industry-report",
   "publisher": "Prospeo",
   "date": null,
   "excerpt": "SOM is the revenue you can realistically capture in 1-3 years. Not a fantasy percentage of SAM.",
   "url": "https://prospeo.io/s/serviceable-obtainable-market",
   "attached": true
  },
  {
   "title": "SAM vs SOM: Key Differences Explained",
   "sourceType": "industry-report",
   "publisher": "VC Beast",
   "date": "2026-03-13",
   "excerpt": "SOM is the portion of SAM you can realistically capture in a defined time period (usually 3-5 years)... Typical SOM is 1-5% of SAM for early-stage companies.",
   "url": "https://vcbeast.com/compare/sam-vs-som",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

